def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    n = len(bins)
    positive_bins = bins[bins > 0]
    avg_capacity = np.mean(positive_bins) if positive_bins.size > 0 else 1
    variance = np.var(positive_bins) if positive_bins.size > 0 else 0.1
    skewness = np.mean((positive_bins - avg_capacity)**3) / (np.std(positive_bins) ** 3 + 1e-9) if positive_bins.size > 1 else 0.0
    for i in range(n):
        capacity = bins[i]
        if capacity <= 0:
            continue
        if item > capacity:
            continue
        ratio = item / capacity
        score = 0.0
        if ratio >= 0.95:
            score = ((1 - ratio) ** 7) * 1.5 + 0.2
            if capacity > avg_capacity * 1.5:
                score *= 0.8
            elif capacity < avg_capacity * 0.7:
                score *= 1.2
        elif 0.7 < ratio < 0.95:
            score = np.log1p((1 - ratio) * 50) * 0.15 + 0.12
            score += (skewness * 0.05) if abs(skewness) > 0.5 else 0
        elif 0.4 < ratio <= 0.7:
            temp = 0.0
            for k in range(1, 12):
                term = ((-1)**k) * (ratio**(k+1)) / (k * 1.3)
                temp += term
            score = abs(temp) + 0.1 + (variance * 0.2)
        else:
            temp = 0.0
            for p in range(1, 15):
                weight = 1 / ((p ** 1.5) + 0.1)
                temp += ((-1) ** (p+1)) * (ratio ** (p + 2)) * weight
            score = abs(temp) + 0.15
        neighbors_influence = 0.0
        neighbors_weights_sum = 0.0
        for offset in range(1, 10):
            neighbor_caps = []
            if i - offset >= 0:
                neighbor_caps.append(bins[i - offset])
            if i + offset < n:
                neighbor_caps.append(bins[i + offset])
            for neighbor_capacity in neighbor_caps:
                if neighbor_capacity > 0:
                    diff = abs(capacity - neighbor_capacity)
                    norm_diff = diff / max(capacity, neighbor_capacity)
                    weight = 1 / (offset ** 2.2)
                    influence = norm_diff * weight
                    if neighbor_capacity > avg_capacity + variance:
                        influence *= 1.15
                    elif neighbor_capacity < avg_capacity - variance:
                        influence *= 0.85
                    if skewness > 1:
                        influence *= 1.05
                    elif skewness < -1:
                        influence *= 0.95
                    neighbors_influence += influence
                    neighbors_weights_sum += weight
        if neighbors_weights_sum > 0:
            neighbors_influence /= neighbors_weights_sum
        cap_factor = (capacity ** 0.65) + (avg_capacity ** 0.35) + (variance * 0.1)
        if cap_factor == 0:
            cap_factor = 1
        penalty = 0
        if capacity < item:
            penalty = ((item - capacity) ** 3.5) * 0.35
        elif capacity > item * 2.3:
            penalty = 0.07
        if i % 5 == 0:
            score *= 0.85
            neighbors_influence *= 1.3
            penalty *= 1.2
        elif i % 3 == 0:
            score *= 1.05
            neighbors_influence *= 0.88
        elif i % 7 == 0:
            score *= 0.9
            neighbors_influence *= 1.1
            penalty *= 1.05
        else:
            score *= 0.93
        priority = score + neighbors_influence / cap_factor + penalty
        if priority < 0:
            priority = 0
        priorities[i] = priority
    finite = priorities[np.isfinite(priorities)]
    if finite.size == 0:
        return priorities
    max_finite = np.max(finite)
    for i in range(n):
        if not np.isfinite(priorities[i]):
            priorities[i] = max_finite * 8
    for _ in range(3):
        new_priorities = priorities.copy()
        for i in range(n):
            if i > 0 and i < n - 1:
                neighboring_avg = (priorities[i-1] + priorities[i+1]) / 2
                new_priorities[i] = (priorities[i] + neighboring_avg) / 2
        priorities = new_priorities
    return priorities
